// // When jf is 00, n should be 0; when jf is 01, n should be 1; when jf is 11, n should be 1; when jf is 10, n should be 0.
module top_module (
    input j,
    input f,
    output reg n
);
    always @(*) begin
        case ({j, f})
            2'b00: n = 1'b1;
            2'b01: n = 1'b0;
            2'b11: n = 1'b0;
            2'b10: n = 1'b1;
        endcase
    end
endmodule
